import time, math
from dataclasses import dataclass, field

@dataclass
class Record:
    text: str
    embedding: list
    importance: float          # 0..1, assigned at write time
    created: float = field(default_factory=time.time)

class AgentMemory:
    def __init__(self, tau_hours=72.0):
        self.records = []
        self.tau = tau_hours * 3600

    def write(self, text, embedding, importance):
        # Skip low-salience noise; only remember what may matter later.
        if importance < 0.2:
            return False
        self.records.append(Record(text, embedding, importance))
        return True

    def read(self, query_emb, k=5, lv=1.0, lr=0.5, li=0.5):
        now = time.time()
        scored = []
        for r in self.records:
            rel = cosine(query_emb, r.embedding)
            rec = math.exp(-(now - r.created) / self.tau)
            scored.append((lv*rel + lr*rec + li*r.importance, r))
        scored.sort(key=lambda x: x[0], reverse=True)
        return [r for _, r in scored[:k]]

def cosine(a, b):
    dot = sum(x*y for x, y in zip(a, b))
    na = math.sqrt(sum(x*x for x in a)); nb = math.sqrt(sum(y*y for y in b))
    return dot / (na*nb + 1e-9)

def consolidate(memory, llm, embed, window=50):
    """Summarise and deduplicate recent memories, then supersede the originals."""
    recent = memory.records[-window:]
    joined = "\n".join(r.text for r in recent)
    summary = llm(f"Summarise these events into durable facts, "
                  f"noting any that update earlier ones:\n{joined}")
    for line in summary.split("\n"):
        if line.strip():
            memory.write(line.strip(), embed(line), importance=0.7)
    # Optionally prune superseded low-importance episodic records here.
